using UnityEngine;
using System;
using System.Collections.Generic;

// PlayerStats.cs - Stores player stats in public variables
public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance;

    public float maxHealth = 100f;
    public float currentHealth = 100f;
    public int currency = 500;
    public int premiumCurrency = 0;
    public int playerLevel = 1;
    public float armor = 0f;
    public float attackPower = 10f;
    public float critChance = 0.05f;
    public float critMultiplier = 1.5f;
    public List<string> ownedItems = new List<string>();

    public event Action<float, float> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnPremiumCurrencyChanged;
    public event Action OnPlayerDied;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public void TakeDamage(float rawDamage)
    {
        float finalDamage = DamageCalculator.CalculateDamage(rawDamage, armor);
        currentHealth = Mathf.Max(0f, currentHealth - finalDamage);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);

        if (currentHealth <= 0f)
        {
            OnPlayerDied?.Invoke();
        }
    }

    public void Heal(float amount)
    {
        currentHealth = Mathf.Min(maxHealth, currentHealth + amount);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            OnCurrencyChanged?.Invoke(currency);
            return true;
        }
        return false;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        OnCurrencyChanged?.Invoke(currency);
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (premiumCurrency >= amount)
        {
            premiumCurrency -= amount;
            OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
            return true;
        }
        return false;
    }

    public void AddPremiumCurrency(int amount)
    {
        premiumCurrency += amount;
        OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
    }

    public void AddOwnedItem(string itemId)
    {
        if (!ownedItems.Contains(itemId))
        {
            ownedItems.Add(itemId);
        }
    }

    public bool OwnsItem(string itemId)
    {
        return ownedItems.Contains(itemId);
    }

    public void SaveStats()
    {
        PlayerPrefs.SetFloat("MaxHealth", maxHealth);
        PlayerPrefs.SetFloat("CurrentHealth", currentHealth);
        PlayerPrefs.SetInt("Currency", currency);
        PlayerPrefs.SetInt("PremiumCurrency", premiumCurrency);
        PlayerPrefs.SetInt("PlayerLevel", playerLevel);
        PlayerPrefs.SetFloat("Armor", armor);
        PlayerPrefs.SetFloat("AttackPower", attackPower);
        PlayerPrefs.SetFloat("CritChance", critChance);
        PlayerPrefs.SetFloat("CritMultiplier", critMultiplier);
        PlayerPrefs.SetString("OwnedItems", string.Join(",", ownedItems));
        PlayerPrefs.Save();
    }

    public void LoadStats()
    {
        maxHealth = PlayerPrefs.GetFloat("MaxHealth", 100f);
        currentHealth = PlayerPrefs.GetFloat("CurrentHealth", 100f);
        currency = PlayerPrefs.GetInt("Currency", 500);
        premiumCurrency = PlayerPrefs.GetInt("PremiumCurrency", 0);
        playerLevel = PlayerPrefs.GetInt("PlayerLevel", 1);
        armor = PlayerPrefs.GetFloat("Armor", 0f);
        attackPower = PlayerPrefs.GetFloat("AttackPower", 10f);
        critChance = PlayerPrefs.GetFloat("CritChance", 0.05f);
        critMultiplier = PlayerPrefs.GetFloat("CritMultiplier", 1.5f);

        string items = PlayerPrefs.GetString("OwnedItems", "");
        ownedItems.Clear();
        if (!string.IsNullOrEmpty(items))
        {
            ownedItems.AddRange(items.Split(','));
        }
    }
}

// DamageCalculator.cs - Client-side damage calculation
public static class DamageCalculator
{
    public static float CalculateDamage(float rawDamage, float armor)
    {
        float damageReduction = armor / (armor + 100f);
        float finalDamage = rawDamage * (1f - damageReduction);
        return Mathf.Max(1f, finalDamage);
    }

    public static float CalculatePlayerAttackDamage(float attackPower, float critChance, float critMultiplier)
    {
        float damage = attackPower;
        bool isCrit = UnityEngine.Random.value <= critChance;
        if (isCrit)
        {
            damage *= critMultiplier;
        }
        return damage;
    }

    public static float CalculateElementalDamage(float baseDamage, ElementType attackElement, ElementType defenseElement)
    {
        float multiplier = GetElementalMultiplier(attackElement, defenseElement);
        return baseDamage * multiplier;
    }

    private static float GetElementalMultiplier(ElementType attack, ElementType defense)
    {
        if (attack == ElementType.Fire && defense == ElementType.Nature) return 1.5f;
        if (attack == ElementType.Nature && defense == ElementType.Water) return 1.5f;
        if (attack == ElementType.Water && defense == ElementType.Fire) return 1.5f;
        if (attack == ElementType.Fire && defense == ElementType.Water) return 0.5f;
        if (attack == ElementType.Water && defense == ElementType.Nature) return 0.5f;
        if (attack == ElementType.Nature && defense == ElementType.Fire) return 0.5f;
        return 1f;
    }
}

public enum ElementType
{
    None,
    Fire,
    Water,
    Nature,
    Light,
    Dark
}

// ShopItem.cs - Defines a purchasable item
[System.Serializable]
public class ShopItem
{
    public string itemId;
    public string itemName;
    public string description;
    public int basePrice;
    public int premiumPrice;
    public bool isPremiumOnly;
    public ShopItemType itemType;
    public float statValue;
    public Sprite icon;
