    public int maxStack;

    public int GetCurrentPrice(int playerLevel)
    {
        return PriceCalculator.CalculatePrice(basePrice, playerLevel);
    }
}

public enum ShopItemType
{
    HealthPotion,
    ArmorUpgrade,
    WeaponUpgrade,
    CritChanceUpgrade,
    CritMultiplierUpgrade,
    MaxHealthUpgrade,
    CurrencyBooster,
    Cosmetic
}

// PriceCalculator.cs - Client-side price calculations
public static class PriceCalculator
{
    public static int CalculatePrice(int basePrice, int playerLevel)
    {
        float levelMultiplier = 1f + (playerLevel - 1) * 0.1f;
        return Mathf.RoundToInt(basePrice * levelMultiplier);
    }

    public static int CalculateUpgradePrice(int basePrice, int currentUpgradeLevel)
    {
        float upgradeMultiplier = Mathf.Pow(1.25f, currentUpgradeLevel);
        return Mathf.RoundToInt(basePrice * upgradeMultiplier);
    }

    public static int CalculateSellPrice(int purchasePrice)
    {
        return Mathf.RoundToInt(purchasePrice * 0.5f);
    }

    public static int CalculateBulkDiscount(int unitPrice, int quantity)
    {
        float discount = 1f;
        if (quantity >= 10) discount = 0.8f;
        else if (quantity >= 5) discount = 0.9f;
        else if (quantity >= 3) discount = 0.95f;

        return Mathf.RoundToInt(unitPrice * quantity * discount);
    }
}

// ShopManager.cs - Handles shop purchases
public class ShopManager : MonoBehaviour
{
    public static ShopManager Instance;

    public List<ShopItem> availableItems = new List<ShopItem>();

    public event Action<ShopItem> OnItemPurchased;
    public event Action<string> OnPurchaseFailed;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        InitializeShopItems();
    }

    private void InitializeShopItems()
    {
        availableItems.Add(new ShopItem
        {
            itemId = "health_potion_small",
            itemName = "Small Health Potion",
            description = "Restores 25 HP",
            basePrice = 50,
            itemType = ShopItemType.HealthPotion,
            statValue = 25f,
            isConsumable = true,
            maxStack = 99
        });

        availableItems.Add(new ShopItem
        {
            itemId = "health_potion_large",
            itemName = "Large Health Potion",
            description = "Restores 75 HP",
            basePrice = 120,
            itemType = ShopItemType.HealthPotion,
            statValue = 75f,
            isConsumable = true,
            maxStack = 99
        });

        availableItems.Add(new ShopItem
        {
            itemId = "armor_upgrade",
            itemName = "Armor Plating",
            description = "Increases armor by 10",
            basePrice = 200,
            itemType = ShopItemType.ArmorUpgrade,
            statValue = 10f,
            isConsumable = false
        });

        availableItems.Add(new ShopItem
        {
            itemId = "weapon_upgrade",
            itemName = "Weapon Enhancement",
            description = "Increases attack power by 5",
            basePrice = 250,
            itemType = ShopItemType.WeaponUpgrade,
            statValue = 5f,
            isConsumable = false
        });

        availableItems.Add(new ShopItem
        {
            itemId = "crit_chance_upgrade",
            itemName = "Lucky Charm",
            description = "Increases crit chance by 2%",
            basePrice = 300,
            itemType = ShopItemType.CritChanceUpgrade,
            statValue = 0.02f,
            isConsumable = false
        });

        availableItems.Add(new ShopItem
        {
            itemId = "max_health_upgrade",
            itemName = "Vitality Boost",
            description = "Increases max health by 20",
            basePrice = 180,
            itemType = ShopItemType.MaxHealthUpgrade,
            statValue = 20f,
            isConsumable = false
        });

        availableItems.Add(new ShopItem
        {
            itemId = "currency_doubler",
            itemName = "Gold Doubler",
            description = "Doubles currency earned for the next battle",
            basePrice = 0,
            premiumPrice = 50,
            isPremiumOnly = true,
            itemType = ShopItemType.CurrencyBooster,
            statValue = 2f,
            isConsumable = true,
            maxStack = 10
        });
    }

    public bool PurchaseItem(string itemId, int quantity = 1)
    {
        ShopItem item = availableItems.Find(i => i.itemId == itemId);
        if (item == null)
        {
            OnPurchaseFailed?.Invoke("Item not found.");
            return false;
        }

        PlayerStats player = PlayerStats.Instance;

        if (item.isPremiumOnly)
        {
            int totalPremiumCost = item.premiumPrice * quantity;
            if (player.SpendPremiumCurrency(totalPremiumCost))
            {
                ApplyItemEffect(item, quantity);
                OnItemPurchased?.Invoke(item);
                return true;
            }
            else
            {
                OnPurchaseFailed?.Invoke("Not enough premium currency.");
                return false;
            }
        }

        int unitPrice = item.GetCurrentPrice(player.playerLevel);
        int totalCost = PriceCalculator.CalculateBulkDiscount(unitPrice, quantity);

        if (player.SpendCurrency(totalCost))
        {
            ApplyItemEffect(item, quantity);
            OnItemPurchased?.Invoke(item);
            player.SaveStats();
            return true;
        }
        else
        {
            OnPurchaseFailed?.Invoke("Not enough currency. Need " + totalCost + " gold.");
            return false;
        }
    }

    private void ApplyItemEffect(ShopItem item, int quantity = 1)
    {
        PlayerStats player = PlayerStats.Instance;

        switch (item.itemType)
        {
            case ShopItemType.HealthPotion:
                player.Heal(item.statValue * quantity);
                break;

            case ShopItemType.ArmorUpgrade:
                player.armor += item.statValue * quantity;
                break;

            case ShopItemType.WeaponUpgrade:
                player.attackPower += item.statValue * quantity;
                break;

            case ShopItemType.CritChanceUpgrade:
                player.critChance = Mathf.Min(1f, player.critChance + item.statValue * quantity);
                break;

            case ShopItemType.CritMultiplierUpgrade:
                player.critMultiplier += item.statValue * quantity;
                break;

            case ShopItemType.MaxHealthUpgrade:
                player.maxHealth += item.statValue * quantity;
                player.currentHealth += item.statValue * quantity;
                break;

            case ShopItemType.CurrencyBooster:
                // Store the booster state for next battle
                PlayerPrefs.SetFloat("CurrencyMultiplier", item.statValue);
                break;
        }

        if (!item.isConsumable)
        {
            player.AddOwnedItem(item.itemId);
        }
    }

    public List<ShopItem> GetAffordableItems()
    {
        List<ShopItem> affordable = new List<ShopItem>();
        PlayerStats player = PlayerStats.Instance;

        foreach (ShopItem item in availableItems)
        {
            if (item.isPremiumOnly)
            {
                if (player.premiumCurrency >= item.premiumPrice)
                    affordable.Add(item);
            }
            else
            {
                if (player.currency >= item.GetCurrentPrice(player.playerLevel))
                    affordable.Add(item);
            }
        }

        return affordable;
    }
}

