// CombatManager.cs - Handles combat and damage application
public class CombatManager : MonoBehaviour
{
    public static CombatManager Instance;

    public float currencyMultiplier = 1f;

    public event Action<float, bool> OnDamageDealt;
    public event Action<int> OnCurrencyEarned;
    public event Action OnBattleWon;
    public event Action OnBattleLost;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        currencyMultiplier = PlayerPrefs.GetFloat("CurrencyMultiplier", 1f);
        // Reset after loading
        PlayerPrefs.SetFloat("CurrencyMultiplier", 1f);
        PlayerPrefs.Save();

        if (PlayerStats.Instance != null)
        {
            PlayerStats.Instance.OnPlayerDied += HandlePlayerDeath;
        }
    }

    public void PlayerAttack(EnemyController enemy)
    {
        PlayerStats player = PlayerStats.Instance;
        bool isCrit = UnityEngine.Random.value <= player.critChance;
        float damage = player.attackPower;

        if (isCrit)
        {
            damage *= player.critMultiplier;
        }

        enemy.TakeDamage(damage);
        OnDamageDealt?.Invoke(damage, isCrit);
    }

    public void PlayerAttackElemental(EnemyController enemy, ElementType playerElement)
    {
        PlayerStats player = PlayerStats.Instance;
        bool isCrit = UnityEngine.Random.value <= player.critChance;
        float damage = player.attackPower;

        if (isCrit)
        {
            damage *= player.critMultiplier;
        }

        damage = DamageCalculator.CalculateElementalDamage(damage, playerElement, enemy.elementType);
        enemy.TakeDamage(damage);
        OnDamageDealt?.Invoke(damage, isCrit);
    }

    public void EnemyAttack(float enemyAttackPower)
    {
        PlayerStats player = PlayerStats.Instance;
        player.TakeDamage(enemyAttackPower);
    }

    public void HandleEnemyDefeated(EnemyController enemy)
    {
        int currencyReward = Mathf.RoundToInt(enemy.currencyReward * currencyMultiplier);
        PlayerStats.Instance.AddCurrency(currencyReward);
        OnCurrencyEarned?.Invoke(currencyReward);

        int xpReward = enemy.xpReward;
        AddExperience(xpReward);
    }

    public void HandleBattleWon(int bonusReward)
    {
        int totalBonus = Mathf.RoundToInt(bonusReward * currencyMultiplier);
        PlayerStats.Instance.AddCurrency(totalBonus);
        OnCurrencyEarned?.Invoke(totalBonus);
        OnBattleWon?.Invoke();
        PlayerStats.Instance.SaveStats();
    }

    private void HandlePlayerDeath()
    {
        OnBattleLost?.Invoke();
        Debug.Log("Player has been defeated!");
    }

    private void AddExperience(int xp)
    {
        // Simple leveling system
        PlayerStats player = PlayerStats.Instance;
        int xpNeeded = player.playerLevel * 100;
        int currentXp = PlayerPrefs.GetInt("CurrentXP", 0) + xp;

        if (currentXp >= xpNeeded)
        {
            player.playerLevel++;
            currentXp -= xpNeeded;
            player.maxHealth += 5f;
            player.currentHealth = player.maxHealth;
            player.attackPower += 1f;
            Debug.Log($"Level Up! Now level {player.playerLevel}");
        }

        PlayerPrefs.SetInt("CurrentXP", currentXp);
    }

    private void OnDestroy()
    {
        if (PlayerStats.Instance != null)
        {
            PlayerStats.Instance.OnPlayerDied -= HandlePlayerDeath;
        }
    }
}

// EnemyController.cs - Enemy behavior
public class EnemyController : MonoBehaviour
{
    public string enemyName = "Enemy";
    public float maxHealth = 50f;
    public float currentHealth = 50f;
    public float attackPower = 8f;
    public float armor = 5f;
    public int currencyReward = 25;
    public int xpReward = 10;
    public float attackInterval = 2f;
    public ElementType elementType = ElementType.None;

    public event Action<float, float> OnEnemyHealthChanged;
    public event Action OnEnemyDefeated;

    private float attackTimer;
    private bool isAlive = true;

    private void Update()
    {
        if (!isAlive) return;

        attackTimer += Time.deltaTime;
        if (attackTimer >= attackInterval)
        {
            attackTimer = 0f;
            Attack();
        }
    }

    public void TakeDamage(float rawDamage)
    {
        if (!isAlive) return;

        float finalDamage = DamageCalculator.CalculateDamage(rawDamage, armor);
        currentHealth = Mathf.Max(0f, currentHealth - finalDamage);
        OnEnemyHealthChanged?.Invoke(currentHealth, maxHealth);

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    private void Attack()
    {
        if (CombatManager.Instance != null)
        {
            CombatManager.Instance.EnemyAttack(attackPower);
        }
    }

    private void Die()
    {
        isAlive = false;
        OnEnemyDefeated?.Invoke();

        if (CombatManager.Instance != null)
        {
            CombatManager.Instance.HandleEnemyDefeated(this);
        }

        Destroy(gameObject, 1f);
    }
}

// GameUIManager.cs - Basic UI management
public class GameUIManager : MonoBehaviour
{
    public UnityEngine.UI.Text healthText;
    public UnityEngine.UI.Text currencyText;
    public UnityEngine.UI.Text premiumCurrencyText;
    public UnityEngine.UI.Text levelText;
    public UnityEngine.UI.Slider healthBar;
    public GameObject shopPanel;
    public GameObject gameOverPanel;

    private void Start()
    {
        PlayerStats player = PlayerStats.Instance;
        if (player != null)
        {
            player.OnHealthChanged += UpdateHealthUI;
            player.OnCurrencyChanged += UpdateCurrencyUI;
            player.OnPremiumCurrencyChanged += UpdatePremiumCurrencyUI;
            player.OnPlayerDied += ShowGameOverScreen;

            UpdateHealthUI(player.currentHealth, player.maxHealth);
            UpdateCurrencyUI(player.currency);
            UpdatePremiumCurrencyUI(player.premiumCurrency);
            UpdateLevelUI();
        }

        if (ShopManager.Instance != null)
        {
            ShopManager.Instance.OnItemPurchased += OnItemBought;
            ShopManager.Instance.OnPurchaseFailed += OnPurchaseFail;
        }

        if (shopPanel != null) shopPanel.SetActive(false);
        if (gameOverPanel != null) gameOverPanel.SetActive(false);
    }

    private void UpdateHealthUI(float current, float max)
    {
        if (healthText != null)
            healthText.text = $"HP: {Mathf.CeilToInt(current)} / {Mathf.CeilToInt(max)}";
        if (healthBar != null)
            healthBar.value = current / max;
    }

    private void UpdateCurrencyUI(int amount)
    {
        if (currencyText != null)
            currencyText.text = $"Gold: {amount}";
    }

    private void UpdatePremiumCurrencyUI(int amount)
    {
        if (premiumCurrencyText != null)
            premiumCurrencyText.text = $"Gems: {amount}";
    }

    private void UpdateLevelUI()
    {
        if (levelText != null && PlayerStats.Instance != null)
            levelText.text = $"Level: {PlayerStats.Instance.playerLevel}";
    }

    public void ToggleShop()
    {
        if (shopPanel != null)
            shopPanel.SetActive(!shopPanel.activeSelf);
    }

    public void OnShopItemClicked(string itemId)
    {
        ShopManager.Instance?.PurchaseItem(itemId);
    }

    private void OnItemBought(ShopItem item)
    {
        Debug.Log($"Purchased: {item.itemName}");
        UpdateLevelUI();
    }

    private void OnPurchaseFail(string reason)
    {
        Debug.Log($"Purchase failed: {reason}");
    }

    private void ShowGameOverScreen()
    {
        if (gameOverPanel != null)
            gameOverPanel.SetActive(true);
    }

    public void OnReviveWithAd()
    {
        // Simulate ad-based revive
        PlayerStats player = PlayerStats.Instance;
        player.currentHealth = player.maxHealth * 0.5f;
        player.OnHealthChanged?.Invoke(player.currentHealth, player.maxHealth);
        if (gameOverPanel != null)
            gameOverPanel.SetActive(false);
    }

    public void OnReviveWithGems()
    {
        PlayerStats player = PlayerStats.Instance;
        if (player.SpendPremiumCurrency(10))
        {
            player.currentHealth = player.maxHealth;
            UpdateHealthUI(player.currentHealth, player.maxHealth);
            if (gameOverPanel != null)
                gameOverPanel.SetActive(false);
        }
    }

    private void OnDestroy()
    {
        PlayerStats player = PlayerStats.Instance;
        if (player != null)
        {
            player.OnHealthChanged -= UpdateHealthUI;
            player.OnCurrencyChanged -= UpdateCurrencyUI;
            player.OnPremiumCurrencyChanged -= UpdatePremiumCurrencyUI;
            player.OnPlayerDied -= ShowGameOverScreen;
        }

        if (ShopManager.Instance != null)
        {
            ShopManager.Instance.OnItemPurchased -= OnItemBought;
            ShopManager.Instance.OnPurchaseFailed -= OnPurchaseFail;
        }
    }
}